const TASK_CURVE={particleCount:24,trailSpan:.68,durationMs:5600,pulseDurationMs:2500,lemniscateA:20,lemniscateBoost:7.5};
function taskCurvePoint(progress,detailScale){const t=progress*Math.PI*2,scale=TASK_CURVE.lemniscateA+detailScale*TASK_CURVE.lemniscateBoost,denom=1+Math.sin(t)**2;return{x:50+scale*Math.cos(t)/denom,y:50+scale*Math.sin(t)*Math.cos(t)/denom}}
