function taskCurveLoader(){return `<svg class="task-curve-loader" viewBox="0 0 100 100" aria-hidden="true"><path class="task-curve-track" stroke-width="4.8"/><g class="task-curve-particles">${Array.from({length:TASK_CURVE.particleCount},()=>"<circle/>").join("")}</g></svg>`}
