function startTaskCurve(root){if(root._taskCurveStarted)return;root._taskCurveStarted=true;const startedAt=performance.now();if(REDUCE_MOTION.matches){paintTaskCurve(root,950);return}function render(now){if(!root.isConnected||root.dataset.terminal==="true"){stopTaskCurve(root);return}paintTaskCurve(root,now-startedAt);root._taskCurveFrame=requestAnimationFrame(render)}root._taskCurveVisibility=()=>{if(document.hidden){cancelAnimationFrame(root._taskCurveFrame);root._taskCurveFrame=0}else if(root._taskCurveStarted&&!root._taskCurveFrame)root._taskCurveFrame=requestAnimationFrame(render)};document.addEventListener("visibilitychange",root._taskCurveVisibility);if(!document.hidden)root._taskCurveFrame=requestAnimationFrame(render)}

function mountBuilder(mode){state.builderMode=mode;state.originalProfile=profileCopy(state.preferences.user_profile);state.draft=profileCopy(state.preferences.user_profile,mode==="first");state.activeStep=mode==="first"?"stage":null;state.activeRoleTab=0;state.activeProvince="";state.completedSteps=new Set(mode==="first"?[]:STEPS);const host=mode==="first"?$("onboarding-builder-host"):$("preferences-builder-host");const other=mode==="first"?$("preferences-builder-host"):$("onboarding-builder-host");const existing=$("radar-builder");if(existing)host.append(existing);else host.append($("radar-builder-template").content.cloneNode(true));other?.classList.add("hidden");host.classList.remove("hidden");bindBuilder();renderBuilder()}

