function renderBuilder(){renderStepState();renderBatchOptions();renderRoleTabs();renderRoleOptions();renderCityOptions();renderKeywords();renderOrganizationOptions();renderCompanies();renderExcludedOptions();renderRadarPreview();const first=state.builderMode==="first",ready=STEPS.every(step=>stepComplete(step)),save=$("save-builder"),actions=save.closest(".builder-actions"),keywordButton=document.querySelector('[data-builder-step="keywords"] .step-continue'),hasSignals=state.draft.custom_keywords.length||state.draft.selected_company_groups.length||state.draft.custom_companies.length;$("cancel-builder").classList.toggle("hidden",first);actions.classList.toggle("hidden",first&&!ready);actions.classList.toggle("action-ready",ready);save.textContent=first?"创建岗位雷达并开始扫描":"保存并重新匹配岗位";if(keywordButton)keywordButton.textContent=hasSignals?"完成配置":"暂不添加，完成配置"}

