function renderRoleOptions(){const sections=state.options?.role_sections||[],query=$("builder-role-search")?.value.trim()||"",items=visibleRoleItems(),selected=items.filter(item=>state.draft.role_groups.includes(item.value)).length,allSelected=Boolean(items.length&&selected===items.length),heading=query?`“${query}”的搜索结果`:sections[state.activeRoleTab]?.label||"细分方向";$("builder-roles").innerHTML=`<div class="role-detail-heading"><div><strong>${escapeHtml(heading)}</strong><span>${items.length} 个细分方向</span></div><button type="button" data-role-select-all aria-pressed="${allSelected}" ${items.length?"":"disabled"}>${allSelected?"取消全选":"全选"}</button></div>${items.length?`<div class="role-options role-option-grid">${items.map(item=>choiceButton("role",item.value,item.label,state.draft.role_groups.includes(item.value))).join("")}</div>`:'<p class="role-empty">没有找到匹配的岗位方向</p>'}`;$("role-selection-count").textContent=`已选择 ${state.draft.role_groups.length} 个方向`;renderChips($("selected-roles"),state.draft.role_groups,"role");$("role-guidance").textContent=state.draft.role_groups.length>5?"当前关注方向较多，后续可能看到更多岗位。":"建议选择 1-5 个核心方向；搜索会同时查找系统联想词。"}
