const ROSE_CURVE={particleCount:78,trailSpan:.26,durationMs:5400,rotationDurationMs:28000,pulseDurationMs:1900,roseA:9.2,roseABoost:.6,roseBreathBase:.72,roseBreathBoost:.28,roseK:5,roseScale:3.25};
