  const modal=$("job-drawer"),panel=modalPanel(),backdrop=modal.querySelector(".job-modal-backdrop");
  if(REDUCE_MOTION.matches||!panel.animate)return;
  const source=modalSourceTransform(trigger,panel),panelFrames=opening?[{transform:source,opacity:.35},{transform:"none",opacity:1}]:[{transform:"none",opacity:1},{transform:source,opacity:0}],backdropFrames=opening?[{opacity:0},{opacity:1}]:[{opacity:1},{opacity:0}];
  modal.classList.add("is-animating");
  await Promise.allSettled([
    panel.animate(panelFrames,{duration:opening?360:260,easing:"cubic-bezier(.22,1,.36,1)",fill:"both"}).finished,
    backdrop.animate(backdropFrames,{duration:opening?260:220,easing:"ease-out",fill:"both"}).finished,
  ]);
  modal.classList.remove("is-animating");
