  const latest=activities.at(-1)||"正在准备本次扫描",fresh=latest!==state.lastTaskActivity,current=task.status==="cancelling"?"正在安全停止扫描":headings[phase],terminal=phase===4;
  ensureTaskPanel();panel.className="task-panel task-workspace";const ring=panel.querySelector(".task-live-ring");if(String(terminal)!==ring.dataset.terminal){stopTaskCurve(ring);ring.dataset.terminal=String(terminal);ring.innerHTML=terminal?icon("check"):taskCurveLoader()}if(terminal)stopTaskCurve(ring);else startTaskCurve(ring);panel.querySelector(".task-label").textContent=terminal?"岗位雷达":"岗位雷达正在工作";panel.querySelector(".task-heading h1").textContent=current;panel.querySelector(".task-heading p").textContent=latest;panel.querySelector('[data-action="cancel-task"]').classList.toggle("hidden",terminal||task.status==="cancelling");const progress=panel.querySelector(".task-progress ol");if(!progress.children.length)progress.innerHTML=steps.map(label=>`<li><span class="task-step-mark" aria-hidden="true"></span><strong>${escapeHtml(label)}</strong></li>`).join("");[...progress.children].forEach((item,index)=>{const number=index+1,status=number<phase||terminal?"done":number===phase?"current":"pending";item.className=status;const marker=item.querySelector(".task-step-mark");if(marker.dataset.status!==status){marker.dataset.status=status;marker.innerHTML=status==="done"?icon("check"):""}});panel.querySelector(".task-activity header span").textContent=`已运行 ${String(Math.floor(elapsed/60)).padStart(2,"0")}:${String(elapsed%60).padStart(2,"0")}`;renderTaskActivities(panel.querySelector(".task-activity-stream"),activities,fresh);
