function clearRadarFilters(){["radar-filter-city","radar-filter-batch","radar-filter-direction"].forEach(id=>$(id).value="");$("radar-sort").value="newest";state.radarPage=1;loadRecommendationPage()}

function openPreferenceBuilder(){if(location.hash==="#preferences")mountBuilder("edit");else location.hash="preferences"}
function bind(){window.addEventListener("hashchange",routeView);$("menu-button").onclick=()=>{const open=$("main-nav").classList.toggle("open");$("menu-button").setAttribute("aria-expanded",String(open))};document.querySelectorAll(".scan-button").forEach(button=>button.onclick=startScan);let timer;["job-search","filter-city","filter-batch","filter-deadline","filter-company-type","job-sort"].forEach(id=>$(id).addEventListener("input",()=>{clearTimeout(timer);timer=setTimeout(()=>{state.page=1;loadJobPage()},220)}));["radar-filter-city","radar-filter-batch","radar-filter-direction","radar-sort"].forEach(id=>$(id).addEventListener("input",()=>{clearTimeout(timer);timer=setTimeout(()=>{state.radarPage=1;loadRecommendationPage()},220)}));$("clear-filters").onclick=clearFilters;$("clear-radar-filters").onclick=clearRadarFilters;$("job-pagination").onclick=event=>{const jump=event.target.closest("[data-page-jump]");if(jump){jumpPage("job");return}const page=Number(event.target.closest("[data-job-page]")?.dataset.jobPage);if(page>=1&&page<=state.pages){state.page=page;loadJobPage()}};$("radar-pagination").onclick=event=>{const jump=event.target.closest("[data-page-jump]");if(jump){jumpPage("radar");return}const page=Number(event.target.closest("[data-radar-page]")?.dataset.radarPage);if(page>=1&&page<=state.radarPages){state.radarPage=page;loadRecommendationPage()}};[$("job-pagination"),$("radar-pagination")].forEach(root=>root.addEventListener("keydown",event=>{if(event.key==="Enter"&&event.target.matches("input")){event.preventDefault();jumpPage(root.id==="job-pagination"?"job":"radar")}}));$("recommendation-tabs").onclick=event=>{const scope=event.target.closest("[data-recommendation-scope]")?.dataset.recommendationScope;if(scope){state.recommendationScope=scope;state.radarPage=1;loadRecommendationPage()}};$("feishu-form").onsubmit=connectFeishu;$("toggle-secret").onclick=()=>{const input=$("app-secret");input.type=input.type==="password"?"text":"password";$("toggle-secret").textContent=input.type==="password"?"显示":"隐藏"};document.body.addEventListener("click",event=>{const target=event.target.closest("[data-action]"),action=target?.dataset.action;if(action==="scan")startScan();if(action==="cancel-task")cancelTask();if(action==="clear-filters")clearFilters();if(action==="load-jobs")loadJobs();if(action==="open-job")openJob(Number(target.dataset.jobId),target);if(action==="close-drawer")closeDrawer();if(action==="edit-preferences")openPreferenceBuilder();if(action==="close-notification")hideHomeNotification();if(action==="rematch")rematchJobs()});document.body.addEventListener("keydown",event=>{if(event.key==="Tab"&&trapModalFocus(event))return;const card=event.target.closest?.(".job-card");if(card&&(event.key==="Enter"||event.key===" ")){event.preventDefault();openJob(Number(card.dataset.jobId),card)}if(event.key==="Escape")closeDrawer()})}
async function initBase(){initLiquidGlass();bind();bindFeishuWizard();bindBaseChoiceGuidance();bindGuideEscape();try{[state.options,state.preferences,state.scanStatus]=await Promise.all([api("/api/onboarding/options"),api("/api/preferences"),api("/api/scan/status")]);$("loading-screen").classList.add("hidden");if(state.preferences.onboarding_complete){showWorkspace(location.hash.slice(1)||"radar");applyScanStatus(state.scanStatus);if(state.scanStatus.state==="running")pollTask(state.scanStatus.active_task.task_id);else await loadJobs()}else{$("onboarding").classList.remove("hidden");mountBuilder("first")}}catch(error){$("loading-screen").innerHTML=empty("应用加载失败",error.message,"重新加载","reload");$("loading-screen").querySelector("button")?.addEventListener("click",()=>location.reload())}}
function showFeishuGuideBase(step=1){state.feishuPreflight=null;$('feishu-connected-panel').classList.add('hidden');$('feishu-wizard').classList.remove('hidden');$('exit-feishu-guide').classList.remove('hidden');setFeishuStep(step)}
function renderFeishuStatus(status){
  state.feishuStatus=status;state.feishuSecretSaved=Boolean(status.secret_saved||status.credentials_saved);
  const connected=Boolean(status.configured&&status.workspace_configured),showConfig=state.feishuSecretSaved,wizard=$("feishu-wizard"),panel=$("feishu-connected-panel"),exit=$("exit-feishu-guide");
  wizard.classList.toggle("hidden",showConfig);panel.classList.toggle("hidden",!showConfig);exit.classList.toggle("hidden",showConfig);exit.textContent=showConfig?"返回配置":"退出引导";
  if(!showConfig){panel.replaceChildren();return}
  const feishu=state.preferences?.feishu||{},summary=status.last_sync_summary||{},created=Number(summary.created||0),updated=Number(summary.updated||0),failed=Number(summary.failed||0),workspace=safeExternalUrl(status.workspace_url),error=feishuErrorText(summary.error||status.last_error);
  panel.innerHTML=`<header class="connected-header"><div><p class="eyebrow">飞书同步</p><h2 id="feishu-connected-title">${connected?escapeHtml(status.workspace_name||"求职工作台"):"配置飞书同步"}</h2><p class="connected-subtitle">${connected?"岗位状态由你维护，最新推荐结果由 JobPicky 同步。":"凭据已保存，直接填写配置即可，不需要重新获取 App Secret。"}</p></div><span class="status-badge ${connected?(failed?"partial":"ready"):"building"}">${connected?(failed?"部分完成":"已连接"):"待完成"}</span></header>${connected?`<section class="sync-status-note ${failed?"partial":"success"}"><strong>${failed?`工作台已创建，${created+updated} 条已写入，${failed} 条失败`:`工作台已创建，已写入 ${created+updated} 条岗位`}</strong>${error?`<span>${escapeHtml(error)}</span>`:""}</section><div class="sync-meta"><span>上次尝试 <b>${escapeHtml(formatDateTime(status.last_sync_at)||"尚未同步")}</b></span><span>完整同步 <b>${escapeHtml(formatDateTime(status.last_successful_sync_at)||"尚无完全成功的同步")}</b></span></div><div class="connected-actions">${workspace?`<a class="button primary" href="${escapeHtml(workspace)}" target="_blank" rel="noopener noreferrer">打开飞书工作台</a>`:""}<button class="button secondary" type="button" data-feishu-action="resync">重新同步最新结果</button></div>`:`<p class="field-hint">保存 Base 链接后会进入只读检查；首次连接才会创建工作台并同步岗位。</p>`}${feishuSettingsMarkup(status,feishu,connected)}<ul class="connection-checks"><li>✓ App Secret 已保存</li>${connected?"<li>✓ 工作台已创建</li>":"<li>○ 等待首次连接</li>"}</ul><button class="danger-link" type="button" data-feishu-action="disconnect">断开飞书连接</button>`;
}
// Keep the guide optional: saved credentials open the compact configuration surface.
function feishuSettingsMarkup(status, feishu, connected){
  return `<details class="feishu-settings" open><summary><span>飞书配置</span><small>留空 App Secret 可继续使用已保存的值</small></summary><div class="feishu-settings-layout"><form id="feishu-settings-form" class="feishu-settings-form"><label>Base 链接<input name="base_url" type="url" value="${escapeHtml(feishu.base_url||"")}" placeholder="https://xxx.feishu.cn/base/xxxxxxxx" required><span>只支持包含 /base/ 的链接。</span></label><label>App ID<input name="app_id" type="text" value="${escapeHtml(feishu.app_id||"")}" autocomplete="off" required></label><label>App Secret<input name="app_secret" type="password" autocomplete="new-password" placeholder="${status.secret_saved?"已保存，留空保持不变":"请输入 App Secret"}" ${status.secret_saved?"":"required"}><span>${status.secret_saved?"已保存的 Secret 不会回显，留空即可继续使用。":"首次填写后会保存到本地配置。"}</span></label><div id="feishu-settings-message" class="form-message hidden" role="alert"></div><button class="button primary" type="submit">保存配置${connected?"":"并继续"}</button></form><aside class="feishu-settings-guide"><span class="settings-guide-label">需要帮助？</span><h3>不知道信息在哪里找</h3><p>查看完整指引，按截图完成飞书应用、权限和 Base 配置；随时可以返回这里继续填写。</p><button class="button ghost" type="button" data-feishu-action="guide">查看完整指引</button></aside></div></details>`;
}
function renderIntegration(){state.feishuSecretSaved=Boolean(state.preferences?.feishu?.secret_saved);renderIntegrationBase()}
function showFeishuGuide(step=1){showFeishuGuideBase(step);$("exit-feishu-guide").textContent=state.feishuSecretSaved?"返回配置":"退出引导"}
function updateCredentialSummary(){
  $("app-id-status").textContent=$("app-id").value.trim()?"已填写":"未填写";
  $("app-secret-status").textContent=$("app-secret").value||state.feishuSecretSaved?"已保存":"未填写";
}
async function saveWizardCredentials(){
  const appId=$("app-id").value.trim(),secret=$("app-secret").value;
  if(!appId||!secret){showFormMessage("请填写 App ID 和 App Secret。","error");return}
  const button=$("feishu-next");setLoading(button,true,"正在保存凭据…");
  let saved=false;
  try{state.preferences=await api("/api/preferences",{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify({feishu:{base_url:$("base-url").value.trim(),app_id:appId,app_secret:secret}})});state.feishuSecretSaved=true;saved=true}catch(error){showFormMessage(error.message,"error")}finally{setLoading(button,false)}
  if(saved)setFeishuStep(4);
}
async function preflightFeishu(){
  const button=$("feishu-preflight"),root=$("preflight-results");state.feishuPreflight=null;
  if(!validateBaseUrl()||!$("app-id").value.trim()||(!$("app-secret").value&&!state.feishuSecretSaved)){root.className="check-results error";root.textContent="请先填写有效的 Base 链接、App ID 和 App Secret。";setFeishuStep(8);return}
  setLoading(button,true,"正在只读检查…");root.className="check-results";root.textContent="正在验证凭据、Base 读取权限和本地岗位库…";
  try{const result=await api("/api/feishu/preflight",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(feishuPayload())});state.feishuPreflight=result;root.className="check-results success";root.innerHTML=result.checks.map(check=>`<p>✓ ${escapeHtml(check.message)}</p>`).join("");$("feishu-preview").innerHTML=`<div><dt>目标 Base</dt><dd>${escapeHtml(result.base_name)}</dd></div><div><dt>工作台</dt><dd>${escapeHtml(result.table_name)}</dd></div><div><dt>本地岗位</dt><dd>${result.baseline_items}</dd></div><div><dt>推荐岗位</dt><dd>${result.recommended_items}</dd></div>`;$("feishu-next").disabled=false}catch(error){root.className="check-results error";root.textContent=error.message}finally{setLoading(button,false)}
}
async function connectFeishu(event){
  event.preventDefault();if(!state.feishuPreflight){showFormMessage("请先返回第 8 步完成只读检查。","error");return}
  const button=$("feishu-submit");setLoading(button,true,"正在创建与同步…");showFormMessage("正在验证连接并准备工作台…","");
  try{const result=await api("/api/feishu/connect",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(feishuPayload())});renderConnectResult(result);localStorage.removeItem("jobpicky.feishuGuideStep");state.preferences=await api("/api/preferences");renderFeishuStatus(await api("/api/feishu/status"))}catch(error){showFormMessage(error.message,"error");[...$("connect-stages").children].forEach(node=>node.classList.remove("active"))}finally{setLoading(button,false)}
}
async function saveFeishuSettings(event){
  event.preventDefault();const form=event.currentTarget,message=$("feishu-settings-message"),data=Object.fromEntries(new FormData(form));
  if(!data.base_url||!data.app_id||(!data.app_secret&&!state.feishuSecretSaved)){message.textContent="请完整填写 Base 链接、App ID 和 App Secret。";message.className="form-message error";return}
  const button=form.querySelector('button[type="submit"]');setLoading(button,true,"正在保存…");
  try{state.preferences=await api("/api/preferences",{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify({feishu:data})});$("base-url").value=data.base_url;$("app-id").value=data.app_id;$("app-secret").value=data.app_secret;state.feishuPreflight=null;const status=await api("/api/feishu/status");renderFeishuStatus(status);if(!status.workspace_configured){showFeishuGuide(8);toast("配置已保存，请完成只读检查")}else toast("配置已保存")}catch(error){message.textContent=error.message;message.className="form-message error"}finally{setLoading(button,false)}
}
async function resyncFeishu(event){
  const button=event.target.closest('[data-feishu-action="resync"]');
  if(!button)return;
  setLoading(button,true,"正在同步…");
  try{await api("/api/feishu/resync",{method:"POST"});renderFeishuStatus(await api("/api/feishu/status"))}catch(error){toast(error.message)}finally{setLoading(button,false)}
}
function bindFeishuWizard(){
  bindFeishuWizardBase();
  $("feishu-next").onclick=async()=>{if(state.feishuStep===3){await saveWizardCredentials();return}if(state.feishuStep===6&&!document.querySelector('[name="base-choice"]:checked')){toast("请选择你是否已有多维表格");return}if(state.feishuStep===8&&!state.feishuPreflight)return;setFeishuStep(state.feishuStep+1)};
  $("feishu-preflight").onclick=preflightFeishu;$("feishu-form").onsubmit=connectFeishu;$("exit-feishu-guide").onclick=()=>{if(state.feishuSecretSaved&&state.feishuStatus)renderFeishuStatus(state.feishuStatus);else location.hash="radar"};
}
function bindFeishuPanelActions(){
  const panel=$("feishu-connected-panel");panel.onclick=event=>{const action=event.target.closest("[data-feishu-action]")?.dataset.feishuAction;if(action==="disconnect")$("disconnect-feishu-dialog").showModal();if(action==="resync")resyncFeishu(event);if(action==="guide"){panel.classList.add("hidden");$("feishu-wizard").classList.remove("hidden");$("exit-feishu-guide").classList.remove("hidden");$("exit-feishu-guide").textContent="返回配置";setFeishuStep(1)}};panel.addEventListener("submit",event=>{if(event.target.id==="feishu-settings-form")saveFeishuSettings(event)});
}

async function init(){
  try{await initBase()}catch(error){
    console.error("JobPicky initialization failed",error);
    const root=$("loading-screen");
    if(root){root.innerHTML=`<div class="loading-error"><strong>页面初始化失败</strong><span>${escapeHtml(error?.message||error||"未知错误")}</span><button class="button secondary" type="button" onclick="location.reload()">重新加载</button></div>`;root.classList.add("error")}
  }
}

init();
bindFeishuPanelActions();
